  3	  getBreakdownByStorageClass,
  4	  ScaleDashboardQuery,
  5	} from '@odf/core/queries';
  6	import { filesystemResource, scResource } from '@odf/core/resources';
  7	import { FileSystemKind } from '@odf/core/types/scale';
  8	import { getStackChartStats } from '@odf/ocs/utils';
  9	import {
 10	  BreakdownCardBody,
 11	  getName,
 12	  getSelectOptions,
 13	  getUID,
 14	  StorageClassResourceKind,
 15	  NamespaceModel,
 16	} from '@odf/shared';
 17	import {
 18	  useCustomPrometheusPoll,
 19	  usePrometheusBasePath,
 20	} from '@odf/shared/hooks/custom-prometheus-poll';
 21	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 22	import {
 23	  getInstantVectorStats,
 24	  humanizeBinaryBytes,
 25	  sortInstantVectorStats,
 26	} from '@odf/shared/utils';
 27	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 28	import * as _ from 'lodash-es';
 29	import { useLocation } from 'react-router-dom-v5-compat';
 30	import {
 31	  MenuToggle,
 32	  MenuToggleElement,
 33	  Select,
 34	  SelectList,
 35	  SelectProps,
 36	} from '@patternfly/react-core';
 37	import { Card, CardBody, CardHeader, CardTitle } from '@patternfly/react-core';
 38	import './CapacityCard.scss';
 39	
 40	export const CapacityCard: React.FC = () => {
 41	  const location = useLocation();
 42	  const pathName = location.pathname;
 43	  return (
 44	    <CapacityCardInternal
 45	      useRemoteFileSystems={!pathName.toLowerCase().includes('san')}
 46	    />
 47	  );
 48	};
 49	
 50	type CapacityCardInternalProps = {
 51	  useRemoteFileSystems: boolean;
 52	};
 53	
 54	const filterScaleStorageClasses = (
 55	  storageClasses: StorageClassResourceKind[],
 56	  fileSystems: FileSystemKind[]
 57	): StorageClassResourceKind[] => {
 58	  const remoteFileSystems = fileSystems.filter(
 59	    (fs) => fs.spec.remote && !_.isEmpty(fs.spec.remote)
 60	  );
 61	  const remoteFileSystemsName = remoteFileSystems.map((fs) => getName(fs));
 62	  const scaleStorageClasses = storageClasses.filter((sc) =>
 63	    remoteFileSystemsName.includes(getName(sc))
 64	  );
 65	  return scaleStorageClasses;
 66	};
 67	
 68	const filterSANStorageClasses = (
 69	  storageClasses: StorageClassResourceKind[],
 70	  fileSystems: FileSystemKind[]
 71	): StorageClassResourceKind[] => {
 72	  const localFileSystems = fileSystems.filter(
 73	    (fs) => fs.spec.local && _.isEmpty(fs.spec.remote)
 74	  );
 75	  const localFileSystemsNames = localFileSystems.map((fs) => getName(fs));
 76	  const scaleStorageClasses = storageClasses.filter((sc) =>
 77	    localFileSystemsNames.includes(getName(sc))
 78	  );
 79	  return scaleStorageClasses;
 80	};
 81	
 82	export const CapacityCardInternal: React.FC<CapacityCardInternalProps> = ({
 83	  useRemoteFileSystems,
 84	}) => {
 85	  const { t } = useCustomTranslation();
 86	  const [storageClassName, setStorageClassName] = React.useState('');
 87	  const [isOpenBreakdownSelect, setBreakdownSelect] = React.useState(false);
 88	
 89	  const [fileSystems, fileSystemsLoaded, fileSystemsError] =
 90	    useK8sWatchResource<FileSystemKind[]>(filesystemResource);
 91	
 92	  const [storageClasses, storageClassesLoaded, storageClassesError] =
 93	    useK8sWatchResource<StorageClassResourceKind[]>(scResource);
 94	
 95	  const filteredStorageClasses = React.useMemo(() => {
 96	    if (
 97	      storageClassesLoaded &&
 98	      !storageClassesError &&
 99	      fileSystemsLoaded &&
100	      !fileSystemsError
101	    ) {
102	      return useRemoteFileSystems
103	        ? filterScaleStorageClasses(storageClasses, fileSystems)
104	        : filterSANStorageClasses(storageClasses, fileSystems);
105	    }
106	    return [];
107	  }, [
108	    storageClasses,
109	    storageClassesLoaded,
110	    storageClassesError,
111	    fileSystems,
112	    fileSystemsLoaded,
113	    fileSystemsError,
114	    useRemoteFileSystems,
115	  ]);
116	
117	  const {
118	    [ScaleDashboardQuery.BY_USED]: queryByUsed,
119	    [ScaleDashboardQuery.TOTAL_USED]: queryTotalUsed,
120	  } = getBreakdownByStorageClass(storageClassName);
121	  const [modelByUsed, modelUsedError, modelUsedLoading] =
122	    useCustomPrometheusPoll({
123	      query: queryByUsed,
124	      endpoint: 'api/v1/query' as any,
125	      basePath: usePrometheusBasePath(),
126	    });
127	  const [modelTotalUsed, modelTotalError, modalTotalLoading] =
128	    useCustomPrometheusPoll({
129	      query: queryTotalUsed,
130	      endpoint: 'api/v1/query' as any,
131	      basePath: usePrometheusBasePath(),
132	    });
133	
134	  React.useEffect(() => {
135	    if (filteredStorageClasses.length > 0 && !storageClassName) {
136	      setStorageClassName(getName(filteredStorageClasses[0]));
137	    }
138	  }, [filteredStorageClasses, storageClassName]);
139	
140	  const dropdownOptions = filteredStorageClasses.map((sc) => ({
141	    name: getName(sc),
142	    id: getUID(sc),
143	  }));
144	
145	  const breakdownSelectItems = getSelectOptions(dropdownOptions);
146	
147	  const queriesLoadError = modelUsedError || modelTotalError;
148	  const dataLoaded = !modelUsedLoading && !modalTotalLoading;
149	
150	  const humanize = humanizeBinaryBytes;
151	  const top6MetricsData = getInstantVectorStats(modelByUsed, 'namespace');
152	  const top5SortedMetricsData = sortInstantVectorStats(top6MetricsData);
153	  const top5MetricsStats = getStackChartStats(top5SortedMetricsData, humanize);
154	  const metricTotal: string = modelTotalUsed?.data?.result?.[0]?.value?.[1];
155	
156	  const handleMetricsChange: SelectProps['onSelect'] = (
157	    _e,
158	    storageClassNameSelection
159	  ) => {
160	    setStorageClassName(storageClassNameSelection as any);
161	    setBreakdownSelect(!isOpenBreakdownSelect);
162	  };
163	
164	  const onToggleClick = () => {
165	    setBreakdownSelect(!isOpenBreakdownSelect);
166	  };
167	
168	  const toggle = (toggleRef: React.Ref<MenuToggleElement>) => (
169	    <MenuToggle
170	      ref={toggleRef}
171	      onClick={onToggleClick}
172	      isExpanded={isOpenBreakdownSelect}
173	      className="scale-capacity-breakdown-card-header__dropdown"
174	      aria-label={t('Break By Dropdown')}
175	      isFullWidth
176	    >
177	      {storageClassName}
178	    </MenuToggle>
179	  );
180	
181	  return (
182	    <Card>
183	      <CardHeader>
184	        <div className="scale-capacity-breakdown-card__header">
185	          <CardTitle id="breakdown-card-title">
186	            {t('Requested Capacity - Namespace (5)')}
187	          </CardTitle>
188	          <Select
189	            id="breakdown-card-metrics-dropdown"
190	            selected={storageClassName}
191	            onSelect={handleMetricsChange}
192	            isOpen={isOpenBreakdownSelect}
193	            toggle={toggle}
194	            shouldFocusToggleOnSelect
195	            popperProps={{ width: 'trigger' }}
196	            onOpenChange={(isOpen) => setBreakdownSelect(isOpen)}
197	          >
198	            <SelectList>{breakdownSelectItems}</SelectList>
199	          </Select>
200	        </div>
201	      </CardHeader>
202	      <CardBody>
203	        <BreakdownCardBody
204	          capacityUsed={metricTotal}
205	          isLoading={!dataLoaded}
206	          hasLoadError={queriesLoadError}
207	          metricTotal={metricTotal}
208	          top5MetricsStats={top5MetricsStats}
209	          metricModel={NamespaceModel}
210	          humanize={humanize}
211	          isPersistentInternal={true}
212	        />
213	      </CardBody>
214	    </Card>
215	  );
216	};
217	
218	export default CapacityCard;

